  1→use std::sync::Mutex;
  2→use tauri::{Emitter, Manager};
  3→#[cfg(desktop)]
  4→use tauri::menu::{Menu, MenuItem, PredefinedMenuItem};
  5→#[cfg(desktop)]
  6→use tauri::tray::{MouseButton, MouseButtonState, TrayIconBuilder, TrayIconEvent};
  7→#[cfg(desktop)]
  8→use tauri_plugin_global_shortcut::{Code, GlobalShortcutExt, Modifiers, Shortcut, ShortcutState};
  9→
 10→struct WindowConfig {
 11→    position_pref: String,
 12→}
 13→
 14→impl Default for WindowConfig {
 15→    fn default() -> Self {
 16→        Self {
 17→            position_pref: "top-third".to_string(),
 18→        }
 19→    }
 20→}
 21→
 22→fn position_top_third(window: &tauri::WebviewWindow) {
 23→    let monitor = window
 24→        .current_monitor()
 25→        .ok()
 26→        .flatten()
 27→        .or_else(|| window.primary_monitor().ok().flatten());
 28→
 29→    if let Some(monitor) = monitor {
 30→        let monitor_size = monitor.size();
 31→        let monitor_pos = monitor.position();
 32→
 33→        if let Ok(window_size) = window.outer_size() {
 34→            let x = monitor_pos.x + (monitor_size.width as i32 - window_size.width as i32) / 2;
 35→            let y = monitor_pos.y + (monitor_size.height as i32) / 5;
 36→
 37→            if let Err(e) = window.set_position(tauri::PhysicalPosition::new(x, y)) {
 38→                eprintln!("failed to position window: {e}");
 39→            }
 40→        }
 41→    } else if let Err(e) = window.center() {
 42→        eprintln!("failed to center window: {e}");
 43→    }
 44→}
 45→
 46→fn show_and_focus(window: &tauri::WebviewWindow) {
 47→    let position_pref = window
 48→        .app_handle()
 49→        .try_state::<Mutex<WindowConfig>>()
 50→        .and_then(|state| state.lock().ok().map(|s| s.position_pref.clone()))
 51→        .unwrap_or_else(|| "top-third".to_string());
 52→
 53→    if position_pref == "center" {
 54→        if let Err(e) = window.center() {
 55→            eprintln!("failed to center window: {e}");
 56→        }
 57→    } else {
 58→        position_top_third(window);
 59→    }
 60→
 61→    if let Err(e) = window.show() {
 62→        eprintln!("failed to show window: {e}");
 63→    }
 64→    if let Err(e) = window.set_focus() {
 65→        eprintln!("failed to focus window: {e}");
 66→    }
 67→}
 68→
 69→fn toggle_window(window: &tauri::WebviewWindow) {
 70→    let visible = window.is_visible().unwrap_or(false);
 71→    let focused = window.is_focused().unwrap_or(false);
 72→
 73→    if visible && focused {
 74→        if let Err(e) = window.hide() {
 75→            eprintln!("failed to hide window: {e}");
 76→        }
 77→    } else if visible {
 78→        if let Err(e) = window.set_focus() {
 79→            eprintln!("failed to focus window: {e}");
 80→        }
 81→    } else {
 82→        show_and_focus(window);
 83→    }
 84→}
 85→
 86→#[tauri::command]
 87→fn set_window_position_pref(state: tauri::State<'_, Mutex<WindowConfig>>, position: String) {
 88→    if let Ok(mut config) = state.lock() {
 89→        config.position_pref = position;
 90→    }
 91→}
 92→
 93→#[cfg_attr(mobile, tauri::mobile_entry_point)]
 94→pub fn run() {
 95→    tauri::Builder::default()
 96→        .manage(Mutex::new(WindowConfig::default()))
 97→        .invoke_handler(tauri::generate_handler![set_window_position_pref])
 98→        .setup(|app| {
 99→            #[cfg(desktop)]
100→            {
101→                let shortcut = Shortcut::new(Some(Modifiers::ALT), Code::Space);
102→                let window = app
103→                    .get_webview_window("main")
104→                    .expect("main window not found");
105→
106→                let window_for_blur = window.clone();
107→                window.on_window_event(move |event| {
108→                    if let tauri::WindowEvent::Focused(false) = event {
109→                        if let Err(e) = window_for_blur.hide() {
110→                            eprintln!("failed to hide on blur: {e}");
111→                        }
112→                    }
113→                });
114→
115→                #[cfg(target_os = "macos")]
116→                {
117→                    use window_vibrancy::{apply_vibrancy, NSVisualEffectMaterial};
118→                    if let Err(e) =
119→                        apply_vibrancy(&window, NSVisualEffectMaterial::HudWindow, None, None)
120→                    {
121→                        eprintln!("failed to apply vibrancy: {e}");
122→                    }
123→                }
124→
125→                position_top_third(&window);
126→
127→                let window_for_shortcut = window.clone();
128→                app.handle().plugin(
129→                    tauri_plugin_global_shortcut::Builder::new()
130→                        .with_handler(move |_app, scut, event| {
131→                            if scut == &shortcut && event.state() == ShortcutState::Pressed {
132→                                toggle_window(&window_for_shortcut);
133→                            }
134→                        })
135→                        .build(),
136→                )?;
137→
138→                app.global_shortcut().register(shortcut)?;
139→
140→                let show_item =
141→                    MenuItem::with_id(app, "show", "Show Raycast", true, None::<&str>)?;
142→                let clipboard_item =
143→                    MenuItem::with_id(app, "clipboard", "Clipboard History", true, None::<&str>)?;
144→                let snippets_item =
145→                    MenuItem::with_id(app, "snippets", "Snippets", true, None::<&str>)?;
146→                let settings_item =
147→                    MenuItem::with_id(app, "settings", "Settings", true, None::<&str>)?;
148→                let check_updates_item = MenuItem::with_id(
149→                    app,
150→                    "check-updates",
151→                    "Check for Updates",
152→                    true,
153→                    None::<&str>,
154→                )?;
155→                let about_item =
156→                    MenuItem::with_id(app, "about", "About Raycast Clone", true, None::<&str>)?;
157→                let quit_item = MenuItem::with_id(app, "quit", "Quit", true, None::<&str>)?;
158→
159→                let menu = Menu::with_items(
160→                    app,
161→                    &[
162→                        &show_item,
163→                        &PredefinedMenuItem::separator(app)?,
164→                        &clipboard_item,
165→                        &snippets_item,
166→                        &settings_item,
167→                        &PredefinedMenuItem::separator(app)?,
168→                        &check_updates_item,
169→                        &about_item,
170→                        &quit_item,
171→                    ],
172→                )?;
173→
174→                let window_for_menu = window.clone();
175→                let window_for_tray = window.clone();
176→
177→                TrayIconBuilder::new()
178→                    .icon(tauri::image::Image::from_bytes(include_bytes!(
179→                        "../icons/tray-icon@2x.png"
180→                    ))?)
181→                    .icon_as_template(true)
182→                    .tooltip("Raycast Clone")
183→                    .menu(&menu)
184→                    .show_menu_on_left_click(false)
185→                    .on_menu_event(move |app, event| match event.id().as_ref() {
186→                        "show" => {
187→                            show_and_focus(&window_for_menu);
188→                        }
189→                        "clipboard" | "snippets" | "settings" | "about" | "check-updates" => {
190→                            show_and_focus(&window_for_menu);
191→                            if let Err(e) =
192→                                app.emit("tray-navigate", event.id().as_ref().to_string())
193→                            {
194→                                eprintln!("failed to emit tray-navigate: {e}");
195→                            }
196→                        }
197→                        "quit" => {
198→                            app.exit(0);
199→                        }
200→                        _ => {}
201→                    })
202→                    .on_tray_icon_event(move |_tray, event| {
203→                        if let TrayIconEvent::Click {
204→                            button: MouseButton::Left,
205→                            button_state: MouseButtonState::Up,
206→                            ..
207→                        } = event
208→                        {
209→                            toggle_window(&window_for_tray);
210→                        }
211→                    })
212→                    .build(app)?;
213→            }
214→
215→            Ok(())
216→        })
217→        .run(tauri::generate_context!())
218→        .expect("error while running tauri application");
219→}
