 76→function loadSettings(themePreference: string): GeneralSettings {
 77→  const stored = storageGet(SETTINGS_STORAGE_KEY, isGeneralSettings);
 78→  if (stored)
 79→    return {
 80→      ...stored,
 81→      appearance: themePreference,
 82→    };
 83→  return {
 84→    ...DEFAULT_SETTINGS,
 85→    appearance: themePreference,
 86→  };
 87→}
