 89→function loadExtensions(): ExtensionEntry[] {
 90→  const states = storageGet(EXTENSIONS_STORAGE_KEY, isBooleanRecord);
 91→  return MOCK_EXTENSIONS.map(ext => ({
 92→    ...ext,
 93→    enabled: states ? (states[ext.id] ?? ext.enabled) : ext.enabled,
 94→  }));
 95→}
